module RefModule(A, B, sub, CK, Y, Cout);input [3:0] A, B;
input sub, CK;
output [3:0] Y;
output Cout;
reg [3:0] Y_reg;
wire [3:0] B_neg;
wire [3:0] B_sub;
wire [4:0] Y_add;

// Invert B and add 1 to obtain two's complement of B
  wire _n01 = ~B[0] ^ 1[0];
  wire _c01 = ~B[0] & 1[0];
  wire _n02 = ~B[1] ^ 1[1] ^ _c01;
  wire _c02 = (~B[1] & 1[1]) | (~B[1] & _c01) | (1[1] & _c01);
  wire _n03 = ~B[2] ^ 1[2] ^ _c02;
  wire _c03 = (~B[2] & 1[2]) | (~B[2] & _c02) | (1[2] & _c02);
  wire _n04 = ~B[3] ^ 1[3] ^ _c03;
  wire _c04 = (~B[3] & 1[3]) | (~B[3] & _c03) | (1[3] & _c03);
  assign B_neg = {_n01, _n02, _n03, _n04};

// Select either B or B_neg based on sub input
assign B_sub = (sub) ? B_neg : B;

// Add A and B_sub
assign Y_add = {1'b0, A} + {1'b0, B_sub};

// Register the sum/difference output
always @(posedge CK) begin
    Y_reg <= Y_add[3:0];
end

// Output the sum/difference and carry/borrow
assign Y = Y_reg;
assign Cout = Y_add[4];

endmodule
